input.command:
cd /app/varsea; f=disks/sub1/subA/subAlpha/ae3f4c.dat;
for off in 1048640 4150370 259920 3145720; do
  echo "==== offset $off ===="; dd if="$f" bs=1 skip=$off count=64 2>/dev/null | od -A d -c;
done

cd /app/varsea; f=disks/sub1/subA/subAlpha/ae3f4c.dat;
echo "== PK\03\04 local headers =="; grep -a -b -o -P 'PK\x03\x04' "$f";
echo "== PK\01\02 central dir =="; grep -a -b -o -P 'PK\x01\x02' "$f";
echo "== PK\05\06 EOCD =="; grep -a -b -o -P 'PK\x05\x06' "$f";
echo "== launchcode occurrences =="; grep -a -b -o "launchcode" "$f"

cd /app/varsea; f=disks/sub1/subA/subAlpha/ae3f4c.dat;
dd if="$f" bs=1 skip=1048576 count=$((3145851-1048576)) 2>/dev/null > /tmp/carved.zip;
ls -la /tmp/carved.zip;
echo "== unzip -l =="; unzip -l /tmp/carved.zip 2>&1 | head;
echo "== zipinfo =="; zipinfo -v /tmp/carved.zip 2>&1 | grep -iE "name|compress|encrypt|size|method" | head -40
